<?php class ActivityLog{private $c;function __construct($db){$this->c=$db;}function all(){$r=$this->c->query("SELECT al.*,u.fullname,u.username,u.role FROM activity_logs al LEFT JOIN users u ON u.id=al.user_id ORDER BY al.created_at DESC LIMIT 300");$d=[];if($r)while($x=$r->fetch_assoc())$d[]=$x;return $d;}function delete($id){$id=intval($id);return $this->c->query("DELETE FROM activity_logs WHERE id=$id");}function clearAll(){return $this->c->query("DELETE FROM activity_logs");}}?>